        "GoVersion": "go1.20.7",
        "Os": "windows",
        "Arch": "amd64",
        "BuildTime": "Mon Sep  4 12:32:48 2023",
        "Context": "default"
    },
    "Server": {
        "Platform": {
            "Name": "Docker Desktop 4.23.0 (120376)"
        },
        "Components": [
            {
                "Name": "Engine",
                "Version": "24.0.6",
                "Details": {
                    "ApiVersion": "1.43",
                    "Arch": "amd64",
                    "BuildTime": "Mon Sep  4 12:32:16 2023",
                    "Experimental": "false",
                    "GitCommit": "1a79695",
                    "GoVersion": "go1.20.7",
                    "KernelVersion": "5.10.102.1-microsoft-standard-WSL2",
